mapper.select:
SELECT r.id, r.building_id, b.name AS building_name, r.room_no, r.status, r.created_at, r.updated_at
FROM dorm_rooms r
JOIN dorm_buildings b ON r.building_id = b.id
WHERE b.name = #{buildingName}
  AND r.room_no = #{roomNo}

mapper.update:
UPDATE dorm_rooms
SET building_id = #{buildingId},
    room_no = #{roomNo},
    status = #{status}
WHERE id = #{id}
